        type: "event",
        content: "type: event_result\nid: \"315069606\"\nprovider: meetup\ntitle: \"Paper reading, vote for papers here: https://tiny.cc/amlsg-vote\"\ndescription: \"\"\nurl: \"https://www.meetup.com/advanced-machine-learning-study-group/events/315069606/\"\ndate_start: \"2026-06-09T19:00:00+02:00\"\ndate_end: \"2026-06-09T21:00:00+02:00\"\ntimezone: Europe/Berlin\nevent_type: ONLINE\nvenue: null\norganizer_id: \"18373067\"\norganizer_name: Advanced Machine Learning Study Group (Virtual)\norganizer_slug: advanced-machine-learning-study-group\nrsvp_count: 2\nis_paid: false\nfee: null\nimage_url: \"https://secure.meetupstatic.com/photos/event/d/a/e/0/highres_460016032.jpeg\"\nhash: 36fc21031e3da7ef\nembed_ref: paper-reading-vote-yH1\napp_id: events\nskill_id: search",
