        embed_id: "c1d12284-6dbb-4f7f-af66-fcb030762aa8",
        type: "event",
        content: "type: event_result\nid: \"315079815\"\nprovider: meetup\ntitle: Pro Session - Watch Me Build AI.com\ndescription: \"This is our one of our paid pro sessions for subscribers of https://watchmebuildai.com.\\n\\nSubscribers can engage directly and watch real websites, tools, products, command centers, and orchestration engines being built in real time.\\n\\nNo lessons, No PowerPoints. Just building, testing, and learning.\\n\\nYou will be sent an AI transcript, but may invite your AI recorder as well.\"\nurl: \"https://www.meetup.com/advanced-ai-concepts-global-berlin/events/315079815/\"\ndate_start: \"2026-06-09T23:00:00+02:00\"\ndate_end: \"2026-06-10T00:00:00+02:00\"\ntimezone: Europe/Berlin\nevent_type: ONLINE\nvenue_name: Online event\nvenue_address: \"\"\nvenue_city: \"\"\nvenue_state: \"\"\nvenue_country: \"\"\nvenue_lat: -8.521147\nvenue_lon: 179.1962\norganizer_id: \"38534610\"\norganizer_name: Advanced AI Concepts - Global - Berlin\norganizer_slug: advanced-ai-concepts-global-berlin\nrsvp_count: 0\nis_paid: true\nfee_amount: 100.0\nfee_currency: USD\nimage_url: \"https://secure.meetupstatic.com/photos/event/1/7/9/6/highres_534546038.jpeg\"\nhash: ca9e804989039aa9\nembed_ref: pro-session-watch-HWp\napp_id: events\nskill_id: search",
